const DEADLINE_LABEL = "31 March 2027";
const DEADLINE_ISO   = "2027-03-31T23:59:59.000+13:00";

function daysToDeadline(): number {
  if (!DEADLINE_ISO) return 0;
  const now = new Date();
  const end = new Date(DEADLINE_ISO);
  return Math.max(0, Math.ceil((end.getTime() - now.getTime()) / 86_400_000));
}

function progressPct(): number {
  if (!DEADLINE_ISO) return 50;
  const start = new Date("2026-04-06T00:00:00Z").getTime();
  const end   = new Date(DEADLINE_ISO).getTime();
  const now   = Date.now();
  const total = end - start;
  const elapsed = Math.max(0, Math.min(total, now - start));
  return Math.round((elapsed / total) * 100);
}

